/* Panglot — skill tree app v3
   - i18next for UI strings
   - PanglotStore for tree state (pub/sub)
   - PanglotAPI for HTTP
   - node.name (target language) replaces title:{fr,en,de}
*/
(() => {
  let T = null;

  function isCustom(n) { return typeof n.id === 'string' && n.id.startsWith('custom-'); }

  function esc(s) {
    return String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
  }

  // ===== i18n =====
  let currentUiLang = localStorage.getItem('panglot.uiLang') || 'fr';
  const uiLangs = [
    { code: 'fr', label: 'Français' },
    { code: 'en', label: 'English' },
    { code: 'de', label: 'Deutsch' }
  ]; // TODO checker ça pour scalabilité
  let availableLangs = []; // Dynamic from API
  const LANG_FLAGS = {
    pol: `<svg viewBox="0 0 18 13" width="18" height="13"><rect width="18" height="6.5" y="0" fill="#fff"/><rect width="18" height="6.5" y="6.5" fill="#DC143C"/></svg>`,
    deu: `<svg viewBox="0 0 18 13" width="18" height="13"><rect width="18" height="4.33" y="0" fill="#000"/><rect width="18" height="4.33" y="4.33" fill="#D00"/><rect width="18" height="4.34" y="8.66" fill="#FC0"/></svg>`,
    tur: `<svg viewBox="0 0 18 13" width="18" height="13"><rect width="18" height="13" fill="#E30A17"/><circle cx="6" cy="6.5" r="3" fill="#fff"/><circle cx="6.8" cy="6.5" r="2.4" fill="#E30A17"/><polygon points="10,5 10.5,6.5 12,6.5 10.8,7.3 11.2,8.8 10,8 8.8,8.8 9.2,7.3 8,6.5 9.5,6.5" fill="#fff"/></svg>`,
    rus: `<svg viewBox="0 0 18 13" width="18" height="13"><rect width="18" height="4.33" y="0" fill="#fff"/><rect width="18" height="4.33" y="4.33" fill="#0039A6"/><rect width="18" height="4.34" y="8.66" fill="#D52B1E"/></svg>`,
    jpn: `<svg viewBox="0 0 18 13" width="18" height="13"><rect width="18" height="13" fill="#fff"/><circle cx="9" cy="6.5" r="3.5" fill="#BC002D"/></svg>`
  };
  const DEFAULT_FLAG = `<svg viewBox="0 0 18 13" width="18" height="13"><rect width="18" height="13" fill="var(--paper-2)"/><path d="M4 6.5h10M9 2a11 11 0 0 0 0 9M9 2a11 11 0 0 1 0 9" stroke="var(--ink-faded)" stroke-width="0.8" fill="none"/><circle cx="9" cy="6.5" r="4.5" stroke="var(--ink-faded)" stroke-width="0.8" fill="none"/></svg>`;

  function getFlag(iso) { return LANG_FLAGS[iso] || DEFAULT_FLAG; }

  function targetLangLabel(iso, autonym) {
    const localized = t('langs.' + iso);
    if (!localized || localized === 'langs.' + iso || localized === autonym) return autonym;
    return `${autonym} — ${localized}`;
  }

  async function initI18n(lang) {
    await i18next.use(i18nextHttpBackend).init({
      lng: lang,
      fallbackLng: 'en',
      backend: { loadPath: 'locales/{{lng}}.json' },
    });
  }

  function t(key, opts) { return i18next.t(key, opts); }

  async function changeLocale(lang) {
    await i18next.changeLanguage(lang);
    currentUiLang = lang;
    localStorage.setItem('panglot.uiLang', lang);
    document.documentElement.lang = lang;
    document.querySelectorAll('[data-i18n]').forEach(el => {
      el.textContent = t(el.getAttribute('data-i18n'));
    });
    document.getElementById('ui-lang-code').textContent = lang.toUpperCase();
    if (T) { renderSidebar(); renderLevels(); renderNodes(); renderEdges(); }
    if (activeNodeId) openPanel(activeNodeId);
  }

  // ===== layout (read from CSS custom properties) =====
  const LAYOUT = { miniColW: 0, rowH: 0, padLeft: 0, padTop: 0, nodeW: 0 };
  function readLayoutFromCss() {
    const cs = getComputedStyle(document.documentElement);
    const read = k => parseFloat(cs.getPropertyValue(k));
    LAYOUT.miniColW = read('--mini-col-w');
    LAYOUT.rowH = read('--row-h');
    LAYOUT.nodeW = read('--node-w');
    LAYOUT.padLeft = read('--pad-left');
    LAYOUT.padTop = read('--pad-top');
  }
  readLayoutFromCss();

  const SUBS_PER_PALIER = 3;
  function palierX(palier) { return LAYOUT.padLeft + palier * SUBS_PER_PALIER * LAYOUT.miniColW; }
  function nodeX(n) { return palierX(n.palier) + n.sub * LAYOUT.miniColW; }

  function computeLayout() {
    const groups = {};
    T.nodes.forEach(n => {
      const key = `${n.palier}_${n.sub}`;
      (groups[key] = groups[key] || []).push(n);
    });
    const catOrder = Object.fromEntries(T.categories.map((c, i) => [c.id, i]));
    const positions = {};
    Object.values(groups).forEach(list => {
      list.sort((a, b) => (catOrder[a.category] ?? 999) - (catOrder[b.category] ?? 999));
      list.forEach((n, idx) => {
        positions[n.id] = {
          x: nodeX(n),
          y: LAYOUT.padTop + idx * LAYOUT.rowH
        };
      });
    });
    return positions;
  }
  let positions = {};
  let prereqIndex = {};

  function buildPrereqIndex() {
    prereqIndex = {};
    T.nodes.forEach(n => {
      (n.prereq || []).forEach(pid => {
        (prereqIndex[pid] = prereqIndex[pid] || new Set()).add(n.id);
      });
    });
  }

  // ===== adequacy zone =====
  function fitZone(n) {
    const lvl = T.nodeLevel(n);
    const d = lvl - T.userFrontier;
    if (n.status === 'mastered') return 'review';
    if (d < -0.3) return 'review';
    if (d <= 0.6) return 'in_zone';
    if (d <= 1.5) return 'ahead';
    return 'beyond';
  }

  // ===== render =====
  const nodesLayer = document.getElementById('nodes-layer');
  const edgesLayer = document.getElementById('edges');
  const satsLayer = document.getElementById('sats-layer');
  const levelsLayer = document.getElementById('levels-layer');

  function statusLabel(s) {
    return t('tree.legend.' + s) || s;
  }
  function catLabel(cat) {
    if (!cat) return 'Custom';
    if (cat.concept_key) {
      const translated = t('concept.' + cat.concept_key);
      if (translated && translated !== 'concept.' + cat.concept_key) return translated;
    }
    return cat.name;
  }

  function renderLevels() {
    levelsLayer.innerHTML = '';
    const totalCols = T.paliers.length * SUBS_PER_PALIER;
    const maxW = LAYOUT.padLeft + totalCols * LAYOUT.miniColW + 200;
    let maxY = LAYOUT.padTop;
    Object.values(positions).forEach(p => { if (p.y > maxY) maxY = p.y; });
    const maxH = maxY + LAYOUT.rowH + 120;
    const canvas = document.getElementById('canvas');
    canvas.style.width = maxW + 'px';
    canvas.style.height = maxH + 'px';
    window._canvasDimensions = { w: maxW, h: maxH };
    applyTransform();

    const palierW = SUBS_PER_PALIER * LAYOUT.miniColW;
    T.paliers.forEach((lv, i) => {
      const div = document.createElement('div');
      div.className = 'level-band';
      const bandX = LAYOUT.padLeft + i * palierW + LAYOUT.nodeW / 2 - palierW / 2;
      div.style.left = bandX + 'px';
      div.style.width = palierW + 'px';
      const lbl = document.createElement('div');
      lbl.className = 'label';
      const parts = lv.label[currentUiLang].split(' · ');
      lbl.innerHTML = `<b>${parts[0]}</b>${parts[1] || ''}`;
      div.appendChild(lbl);

      for (let s = 0; s < SUBS_PER_PALIER; s++) {
        const tick = document.createElement('div');
        tick.className = 'sub-tick';
        tick.style.left = (s * LAYOUT.miniColW) + 'px';
        tick.innerHTML = `<span>${lv.label.en.split(' · ')[0]}.${s + 1}</span>`;
        div.appendChild(tick);
      }

      levelsLayer.appendChild(div);
    });

    const frontier = document.createElement('div');
    frontier.className = 'frontier-line';
    const fx = LAYOUT.padLeft + T.userFrontier * SUBS_PER_PALIER * LAYOUT.miniColW + LAYOUT.nodeW / 2;
    frontier.style.left = fx + 'px';
    frontier.innerHTML = `
      <div class="frontier-label">
        <span class="frontier-dot"></span>
        <span>${t('frontier.label')}</span>
      </div>`;
    levelsLayer.appendChild(frontier);
  }

  function renderNodes() {
    nodesLayer.innerHTML = '';
    const reco = T.nodes.find(n => fitZone(n) === 'in_zone' && n.status === 'in_progress') ||
      T.nodes.find(n => fitZone(n) === 'in_zone');
    const recoId = reco ? reco.id : null;

    T.nodes.forEach(n => {
      const p = positions[n.id];
      if (!p) return;
      const el = document.createElement('div');
      const zone = fitZone(n);
      el.className = `node status-${n.status} zone-${zone}`;
      if (isCustom(n)) el.classList.add('custom');
      if (!n.is_generatable) el.classList.add('branch-node');
      if (activeCatFilter && n.category !== activeCatFilter) el.classList.add('cat-dimmed');
      el.dataset.id = n.id;
      el.style.left = p.x + 'px';
      el.style.top = p.y + 'px';

      const cat = T.categories.find(c => c.id === n.category);
      const sealIx = T.categories.findIndex(c => c.id === n.category);
      const seals = ['Ph', 'Gr', 'Lx', 'Cj', 'Sy'];
      const sealLetter = cat ? (seals[sealIx] || '?') : '⊕';
      const hue = cat ? cat.hue : 80;
      const isMastered = n.status === 'mastered';
      const sealStyle = isMastered
        ? `background: oklch(96% 0.04 ${hue}); color: oklch(32% 0.12 ${hue}); border-color: transparent;`
        : `background: oklch(94% 0.035 ${hue}); color: oklch(35% 0.12 ${hue}); border-color: oklch(78% 0.06 ${hue});`;

      let practicedHtml = '';
      if (n.lastPracticed != null && n.status !== 'fresh') {
        const d = n.lastPracticed;
        const label = d === 0 ? t('time.today')
          : d === 1 ? t('time.yesterday')
            : d < 7 ? t('time.days_ago', { count: d })
              : d < 30 ? t('time.weeks_ago', { count: Math.round(d / 7) })
                : t('time.over_month');
        practicedHtml = `<div class="n-practiced" title="${n.lastPracticed}j">◷ ${label}</div>`;
      }

      let zoneBadge = '';
      if (zone === 'ahead' || zone === 'beyond') {
        zoneBadge = `<div class="n-zone-badge zone-${zone}" title="${t('zone.' + zone + '.hint')}">${zone === 'beyond' ? '↯' : '↗'} ${t('zone.' + zone + '.label')}</div>`;
      }
      if (zone === 'review' && n.status === 'mastered' && n.lastPracticed > 14) {
        zoneBadge = `<div class="n-zone-badge zone-staleish" title="${t('zone.review.hint')}">◷ ${t('revisit')}</div>`;
      }

      el.innerHTML = `
        ${n.id === recoId ? `<div class="reco">${t('reco')}</div>` : ''}
        ${zoneBadge}
        ${isCustom(n) ? `<div class="n-custom-mark" title="Nœud personnalisé">∿</div>` : ''}
        <div class="n-head">
          <div class="seal" style="${sealStyle}">${sealLetter}</div>
          <div class="n-title">${esc(n.name)}</div>
        </div>
        <div class="n-native">${esc(n.native)}</div>
        <div class="n-meta">
          <span>${statusLabel(n.status)}</span>
          <span>${Math.round((n.mastery || 0) * 100)}%</span>
        </div>
        <div class="n-bar-track">
          <div class="n-bar-fill" style="width: ${(n.mastery || 0) * 100}%;"></div>
        </div>
        ${practicedHtml}
      `;

      el.addEventListener('click', (e) => { e.stopPropagation(); openPanel(n.id); });
      el.addEventListener('mouseenter', () => highlightChain(n.id));
      el.addEventListener('mouseleave', () => clearHighlight());

      nodesLayer.appendChild(el);
    });
  }

  function renderEdges() {
    const svg = edgesLayer;
    const maxW = parseInt(document.getElementById('canvas').style.width);
    const maxH = parseInt(document.getElementById('canvas').style.height);
    svg.setAttribute('width', maxW);
    svg.setAttribute('height', maxH);
    svg.innerHTML = '';

    T.nodes.forEach(n => {
      (n.prereq || []).forEach(preId => {
        const from = positions[preId];
        const to = positions[n.id];
        if (!from || !to) return;
        const x1 = from.x + LAYOUT.nodeW;
        const y1 = from.y + 40;
        const x2 = to.x;
        const y2 = to.y + 40;
        const dx = (x2 - x1);
        const cx1 = x1 + dx * 0.5;
        const cx2 = x2 - dx * 0.5;
        const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
        path.setAttribute('d', `M ${x1} ${y1} C ${cx1} ${y1}, ${cx2} ${y2}, ${x2} ${y2}`);
        path.classList.add('edge');
        const zone = fitZone(n);
        if (zone === 'ahead') path.classList.add('edge-ahead');
        if (zone === 'beyond') path.classList.add('edge-beyond');
        if (activeCatFilter) {
          const fromNode = T.nodes.find(x => x.id === preId);
          if (fromNode?.category !== activeCatFilter && n.category !== activeCatFilter) {
            path.classList.add('cat-dimmed');
          }
        }
        path.dataset.from = preId;
        path.dataset.to = n.id;
        svg.appendChild(path);
      });
    });
  }

  function highlightChain(id) {
    const prereqs = new Set(), unlocks = new Set();
    function collectUp(nid) {
      const node = T.nodes.find(n => n.id === nid);
      if (!node) return;
      (node.prereq || []).forEach(p => { prereqs.add(p); collectUp(p); });
    }
    function collectDown(nid) {
      (prereqIndex[nid] || new Set()).forEach(childId => { unlocks.add(childId); collectDown(childId); });
    }
    collectUp(id); collectDown(id);
    const active = new Set([id, ...prereqs, ...unlocks]);

    document.querySelectorAll('.node').forEach(el => {
      el.classList.toggle('dim', !active.has(el.dataset.id));
    });
    document.querySelectorAll('.edge').forEach(p => {
      const from = p.dataset.from, to = p.dataset.to;
      if (active.has(from) && active.has(to)) p.classList.add('active');
      else p.classList.add('dim');
    });
  }
  function clearHighlight() {
    document.querySelectorAll('.node.dim').forEach(el => el.classList.remove('dim'));
    document.querySelectorAll('.edge.active, .edge.dim').forEach(p => { p.classList.remove('active'); p.classList.remove('dim'); });
  }

  // ===== semantic zoom state =====
  let viewMode = 'micro'; // 'macro' | 'micro'
  let activeCatFilter = null;
  const macroLayer = document.getElementById('macro-layer');

  // ===== satellites =====
  let activeNodeId = null;
  function renderSatellites(nodeId) {
    satsLayer.innerHTML = '';
    if (!nodeId) return;
    const node = T.nodes.find(n => n.id === nodeId);
    if (!node) return;
    const decks = node.decks || [];
    const p = positions[nodeId];
    if (!p) return;
    const cx = p.x + LAYOUT.nodeW / 2;
    const cy = p.y + 60;
    const R = 180;
    decks.forEach((d, i) => {
      const n = decks.length;
      const baseAngle = -Math.PI / 2;
      const spread = Math.PI * 0.85;
      const angle = baseAngle - spread / 2 + (n === 1 ? spread / 2 : (i / (n - 1)) * spread);
      const sx = cx + Math.cos(angle) * R;
      const sy = cy + Math.sin(angle) * R;
      const pill = document.createElement('div');
      pill.className = 'deck-sat';
      pill.style.left = sx + 'px';
      pill.style.top = sy + 'px';
      pill.innerHTML = `<span>${d}</span>`;
      satsLayer.appendChild(pill);

      const linkSvg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
      linkSvg.classList.add('sat-link');
      linkSvg.style.position = 'absolute';
      linkSvg.style.left = '0'; linkSvg.style.top = '0';
      linkSvg.setAttribute('width', parseInt(document.getElementById('canvas').style.width));
      linkSvg.setAttribute('height', parseInt(document.getElementById('canvas').style.height));
      const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
      path.setAttribute('d', `M ${cx} ${cy} L ${sx} ${sy}`);
      linkSvg.appendChild(path);
      satsLayer.appendChild(linkSvg);

      requestAnimationFrame(() => {
        pill.classList.add('show');
        linkSvg.classList.add('show');
      });
    });
  }

  // ===== semantic zoom =====
  function renderMacro() {
    viewMode = 'macro';
    activeCatFilter = null;
    panel.classList.remove('open');
    activeNodeId = null;
    satsLayer.innerHTML = '';

    nodesLayer.style.display = 'none';
    edgesLayer.style.display = 'none';
    levelsLayer.style.display = 'none';
    macroLayer.style.display = '';
    macroLayer.innerHTML = '';

    document.getElementById('view-breadcrumb').classList.add('hidden');
    document.getElementById('btn-add-node').style.display = 'none';
    document.getElementById('zoom-macro').classList.add('on');

    const BUBBLE_W = 220, BUBBLE_H = 110;
    const canvasW = parseInt(document.getElementById('canvas').style.width) || 2000;
    const canvasH = parseInt(document.getElementById('canvas').style.height) || 800;

    // Avg X per category from existing node positions, fixed 2-row Y layout
    const bubblePos = {};
    T.categories.forEach((cat, idx) => {
      const catNodes = T.nodes.filter(n => n.category === cat.id && positions[n.id]);
      if (!catNodes.length) return;
      const avgX = catNodes.reduce((s, n) => s + positions[n.id].x, 0) / catNodes.length;
      const row = idx % 2;
      bubblePos[cat.id] = {
        x: Math.max(LAYOUT.padLeft, avgX - BUBBLE_W / 2),
        y: 140 + row * (BUBBLE_H + 32),
      };
    });

    // Inter-category dependency edges
    const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
    svg.classList.add('macro-edges-svg');
    svg.setAttribute('width', canvasW);
    svg.setAttribute('height', canvasH);
    const catEdgePairs = new Set();
    T.nodes.forEach(n => {
      (n.prereq || []).forEach(pid => {
        const pn = T.nodes.find(x => x.id === pid);
        if (pn && pn.category && n.category && pn.category !== n.category) {
          catEdgePairs.add(`${pn.category}→${n.category}`);
        }
      });
    });
    catEdgePairs.forEach(pair => {
      const [fromId, toId] = pair.split('→');
      const from = bubblePos[fromId], to = bubblePos[toId];
      if (!from || !to) return;
      const x1 = from.x + BUBBLE_W, y1 = from.y + BUBBLE_H / 2;
      const x2 = to.x,              y2 = to.y + BUBBLE_H / 2;
      const dx = x2 - x1;
      const p = document.createElementNS('http://www.w3.org/2000/svg', 'path');
      p.setAttribute('d', `M ${x1} ${y1} C ${x1 + dx * 0.5} ${y1}, ${x2 - dx * 0.5} ${y2}, ${x2} ${y2}`);
      p.classList.add('macro-edge-path');
      svg.appendChild(p);
    });
    macroLayer.appendChild(svg);

    // Render bubbles
    T.categories.forEach(cat => {
      const catNodes = T.nodes.filter(n => n.category === cat.id);
      if (!catNodes.length) return;
      const pos = bubblePos[cat.id];
      if (!pos) return;
      const mastered = catNodes.filter(n => n.status === 'mastered').length;
      const inProgress = catNodes.filter(n => n.status === 'in_progress').length;
      const avgMastery = catNodes.reduce((s, n) => s + (n.mastery || 0), 0) / catNodes.length;
      const hue = cat.hue;
      const label = catLabel(cat);
      const firstLetter = (cat.concept_key || label)[0].toUpperCase();

      const bubble = document.createElement('div');
      bubble.className = 'macro-bubble';
      bubble.style.left = pos.x + 'px';
      bubble.style.top = pos.y + 'px';
      bubble.innerHTML = `
        <div class="mb-header">
          <div class="mb-seal" style="background:oklch(94% 0.035 ${hue});color:oklch(35% 0.12 ${hue});border-color:oklch(78% 0.06 ${hue});">${esc(firstLetter)}</div>
          <div class="mb-name">${esc(label)}</div>
        </div>
        <div class="mb-stats">
          <span class="mb-count">${catNodes.length} nœuds</span>
          <span class="mb-mastered">${mastered} maîtrisés</span>
          ${inProgress ? `<span class="mb-inprogress">${inProgress} en cours</span>` : ''}
        </div>
        <div class="mb-bar-track"><div class="mb-bar-fill" style="width:${Math.round(avgMastery * 100)}%;background:oklch(58% 0.12 ${hue});"></div></div>
        <div class="mb-pct">${Math.round(avgMastery * 100)}% maîtrisé</div>
      `;
      bubble.addEventListener('click', () => drillInto(cat.id));
      macroLayer.appendChild(bubble);
    });

    // Resize canvas to fit bubbles
    const rights = Object.values(bubblePos).map(p => p.x + BUBBLE_W + LAYOUT.padLeft);
    const bottoms = Object.values(bubblePos).map(p => p.y + BUBBLE_H + 60);
    document.getElementById('canvas').style.width = Math.max(canvasW, ...rights) + 'px';
    document.getElementById('canvas').style.height = Math.max(300, ...bottoms) + 'px';
  }

  function drillInto(catId) {
    viewMode = 'micro';
    activeCatFilter = catId;
    macroLayer.style.display = 'none';
    nodesLayer.style.display = '';
    edgesLayer.style.display = '';
    levelsLayer.style.display = '';
    document.getElementById('btn-add-node').style.display = '';
    document.getElementById('zoom-macro').classList.remove('on');

    renderLevels(); renderNodes(); renderEdges();

    const cat = T.categories.find(c => c.id === catId);
    const bc = document.getElementById('view-breadcrumb');
    bc.classList.remove('hidden');
    bc.querySelector('.bc-cat').textContent = catLabel(cat);

    // Scroll to leftmost node of this category
    const catNodes = T.nodes.filter(n => n.category === catId && positions[n.id]);
    if (catNodes.length) {
      const minX = Math.min(...catNodes.map(n => positions[n.id].x));
      const stage = document.getElementById('stage');
      stage.scrollLeft = Math.max(0, minX - 60);
      stage.scrollTop = 0;
    }
  }

  function exitMacroFilter() {
    viewMode = 'micro';
    activeCatFilter = null;
    macroLayer.style.display = 'none';
    nodesLayer.style.display = '';
    edgesLayer.style.display = '';
    levelsLayer.style.display = '';
    document.getElementById('view-breadcrumb').classList.add('hidden');
    document.getElementById('btn-add-node').style.display = '';
    document.getElementById('zoom-macro').classList.remove('on');
    renderLevels(); renderNodes(); renderEdges();
  }

  // ===== pan & zoom =====
  const stage = document.getElementById('stage');
  const canvas = document.getElementById('canvas');
  let vx = 0, vy = 0, vscale = 1;
  function applyTransform() {
    canvas.style.transform = `scale(${vscale})`;
    const dims = window._canvasDimensions || { w: parseInt(canvas.style.width), h: parseInt(canvas.style.height) };
    if (vscale > 1) {
      canvas.style.width = (dims.w * vscale) + 'px';
      canvas.style.height = (dims.h * vscale) + 'px';
    } else {
      canvas.style.width = dims.w + 'px';
      canvas.style.height = dims.h + 'px';
    }
  }
  function zoom(factor) {
    vscale = Math.max(0.4, Math.min(3.5, vscale * factor));
    applyTransform();
  }
  function fitView() {
    vscale = 1;
    applyTransform();
  }
  document.getElementById('zoom-in').onclick = () => zoom(1.2);
  document.getElementById('zoom-out').onclick = () => zoom(1 / 1.2);
  document.getElementById('zoom-fit').onclick = fitView;
  const focusBtn = document.getElementById('zoom-focus');
  if (focusBtn) focusBtn.onclick = focusFrontier;
  document.getElementById('zoom-macro').onclick = () => {
    if (viewMode === 'macro') exitMacroFilter();
    else renderMacro();
  };
  document.getElementById('bc-back').onclick = exitMacroFilter;

  function focusFrontier() {
    if (!T) return;
    const fx = LAYOUT.padLeft + T.userFrontier * SUBS_PER_PALIER * LAYOUT.miniColW;
    stage.scrollLeft = fx - 20; // Aligns slightly before the frontier
  }


  stage.addEventListener('wheel', (e) => {
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      const factor = e.deltaY < 0 ? 1.1 : 1 / 1.1;
      zoom(factor);
      return;
    }
  }, { passive: false });


  // ===== panel =====
  const panel = document.getElementById('panel');
  function openPanel(id) {
    activeNodeId = id;
    const node = T.nodes.find(n => n.id === id);
    if (!node) return;
    const zone = fitZone(node);
    const palierLabel = T.paliers[node.palier].label[currentUiLang];
    const subLabel = `${palierLabel.split(' · ')[0]}.${node.sub + 1}`;
    const cat = T.categories.find(c => c.id === node.category);
    document.getElementById('p-cat').textContent = catLabel(cat);
    document.getElementById('p-lvl').textContent = subLabel;
    document.getElementById('p-status').textContent = statusLabel(node.status);
    document.getElementById('p-title').textContent = node.name;
    document.getElementById('p-native').textContent = node.native || '';
    const descEl = document.getElementById('p-desc');
    if (descEl) { descEl.textContent = node.desc || ''; descEl.hidden = !node.desc; }
    document.getElementById('p-mastery').textContent = Math.round((node.mastery || 0) * 100);
    document.getElementById('p-xdone').textContent = node.exercisesDone || 0;

    const fitBanner = document.getElementById('p-fit');
    fitBanner.className = `fit-banner zone-${zone}`;
    fitBanner.innerHTML = `
      <div class="fit-icon">${zone === 'beyond' ? '↯' : zone === 'ahead' ? '↗' : zone === 'review' ? '◷' : '●'}</div>
      <div class="fit-text">
        <div class="fit-title">${t('zone.' + zone + '.label')}</div>
        <div class="fit-hint">${t('zone.' + zone + '.hint')}</div>
      </div>
    `;

    const dEl = document.getElementById('p-decks');
    dEl.innerHTML = '';
    (node.decks || []).forEach((d, i) => {
      const row = document.createElement('div');
      row.className = 'deck-item';
      const exCount = 6 + ((i * 7) % 14);
      row.innerHTML = `
        <div class="deck-num">${String(i + 1).padStart(2, '0')}</div>
        <div class="deck-title">${d}</div>
        <div class="deck-meta">${exCount} ex.</div>
      `;
      dEl.appendChild(row);
    });
    if (!node.decks?.length) dEl.innerHTML = '<span style="color:var(--ink-faded); font-size:12px;">—</span>';

    const prEl = document.getElementById('p-prereq');
    prEl.innerHTML = '';
    (node.prereq || []).forEach(pid => {
      const pn = T.nodes.find(n => n.id === pid);
      if (!pn) return;
      const chip = document.createElement('button');
      chip.className = 'req-chip' + (pn.status === 'mastered' ? ' done' : '');
      chip.textContent = pn.name;
      chip.onclick = () => openPanel(pid);
      prEl.appendChild(chip);
    });
    if (!node.prereq?.length) prEl.innerHTML = '<span style="color:var(--ink-faded); font-size:12px;">—</span>';

    const unEl = document.getElementById('p-unlocks');
    unEl.innerHTML = '';
    T.nodes.filter(n => (n.prereq || []).includes(id)).forEach(un => {
      const chip = document.createElement('button');
      chip.className = 'req-chip';
      chip.textContent = un.name;
      chip.onclick = () => openPanel(un.id);
      unEl.appendChild(chip);
    });
    if (!unEl.children.length) unEl.innerHTML = '<span style="color:var(--ink-faded); font-size:12px;">—</span>';

    const btn = document.getElementById('btn-start');
    if (!node.is_generatable) {
      btn.disabled = true;
      btn.textContent = t('node.branch_hint');
    } else {
      btn.disabled = false;
      if (node.status === 'mastered') btn.textContent = t('node.review');
      else if (node.status === 'in_progress') btn.textContent = t('node.continue');
      else btn.textContent = t('node.start');
    }

    btn.onclick = async () => {
      btn.disabled = true;
      const origLabel = btn.textContent;
      btn.textContent = '…';
      try {
        const result = await PanglotAPI.generateForNode(node.id, T.language.code);
        if (result.success && result.cards?.length) {
          alert(`${result.cards.length} carte(s) générée(s) pour «${node.name}»`);
        } else {
          alert(result.message || 'Erreur lors de la génération');
        }
      } catch (e) {
        alert('Impossible de joindre le serveur');
      } finally {
        btn.disabled = false;
        btn.textContent = origLabel;
      }
    };

    const delBtn = document.getElementById('btn-delete');
    const nodeIsCustom = isCustom(node);
    delBtn.style.display = nodeIsCustom ? '' : 'none';
    if (nodeIsCustom) {
      delBtn.onclick = async () => {
        if (!confirm(t('node.delete_confirm'))) return;
        const ok = await PanglotStore.deleteCustomization(node.id);
        if (!ok) { alert('Suppression échouée'); return; }
        panel.classList.remove('open');
        activeNodeId = null;
      };
    }

    panel.classList.add('open');
    document.querySelectorAll('.node').forEach(el => el.classList.toggle('active', el.dataset.id === id));
    renderSatellites(id);
  }
  document.getElementById('panel-close').onclick = () => {
    panel.classList.remove('open');
    document.querySelectorAll('.node').forEach(el => el.classList.remove('active'));
    satsLayer.innerHTML = '';
    activeNodeId = null;
  };
  stage.addEventListener('click', (e) => {
    if (e.target === stage || e.target.classList.contains('canvas')) {
      document.getElementById('panel-close').click();
    }
  });

  // ===== sidebar =====
  function renderSidebar() {
    const all = T.nodes;
    const mastered = all.filter(n => n.status === 'mastered').length;
    const total = all.length || 1;
    const overall = Math.round((mastered / total) * 100);
    document.getElementById('overall-pct').textContent = overall;
    document.getElementById('overall-caption').textContent = t('sidebar.nodes_mastered', { mastered, total });

    const lvEl = document.getElementById('level-rows');
    lvEl.innerHTML = '';
    T.paliers.forEach((lv, i) => {
      const levelNodes = all.filter(n => n.palier === i);
      const avg = levelNodes.length ? levelNodes.reduce((s, n) => s + (n.mastery || 0), 0) / levelNodes.length : 0;
      const row = document.createElement('div');
      row.className = 'level-bar';
      row.innerHTML = `
        <span class="lv">${lv.label.en.split(' · ')[0]}</span>
        <span class="track"><span class="fill" style="width:${Math.round(avg * 100)}%"></span></span>
        <span class="pct">${Math.round(avg * 100)}%</span>
      `;
      lvEl.appendChild(row);
    });

    const catEl = document.getElementById('cat-list');
    catEl.innerHTML = '';
    T.categories.forEach(c => {
      const ns = all.filter(n => n.category === c.id);
      const m = ns.filter(n => n.status === 'mastered').length;
      const row = document.createElement('div');
      row.className = 'cat-row' + (activeCatFilter === c.id ? ' active' : '');
      row.innerHTML = `
        <span class="cat-swatch" style="color: oklch(58% 0.12 ${c.hue});"></span>
        <span>${esc(catLabel(c))}</span>
        <span class="cat-count">${m}/${ns.length}</span>
      `;
      row.addEventListener('click', () => {
        if (activeCatFilter === c.id) exitMacroFilter();
        else drillInto(c.id);
      });
      catEl.appendChild(row);
    });

    const curTarget = availableLangs.find(l => l.iso === T.language.code);
    document.getElementById('lang-flag').innerHTML = getFlag(T.language.code);
    document.getElementById('lang-native').textContent = curTarget ? targetLangLabel(curTarget.iso, curTarget.autonym) : T.language.native;
  }

  // ===== add node form =====
  const addForm = document.getElementById('add-node-form');
  document.getElementById('btn-add-node').onclick = () => {
    addForm.classList.toggle('show');
    const first = addForm.querySelector('input[name=title]');
    if (first) setTimeout(() => first.focus(), 100);
  };
  document.getElementById('add-close').onclick = () => addForm.classList.remove('show');
  function populateAddSelects() {
    const catSel = addForm.querySelector('select[name=category]');
    catSel.innerHTML = T.categories.map(c => `<option value="${esc(c.id)}">${esc(catLabel(c))}</option>`).join('');
    const palSel = addForm.querySelector('select[name=palier]');
    palSel.innerHTML = T.paliers.map((p, i) =>
      [0, 1, 2].map(s => `<option value="${i}_${s}">${p.label.en.split(' · ')[0]}.${s + 1}</option>`).join('')
    ).join('');
    const prBox = addForm.querySelector('.prereq-check');
    prBox.innerHTML = T.nodes.map(n => `
      <label><input type="checkbox" value="${esc(n.id)}"> ${esc(n.name)}</label>
    `).join('');
  }
  document.getElementById('add-submit').onclick = async () => {
    const title = addForm.querySelector('[name=title]').value.trim();
    const cat = addForm.querySelector('[name=category]').value;
    const prereq = [...addForm.querySelectorAll('.prereq-check input:checked')].map(x => x.value);
    if (!title) { addForm.querySelector('[name=title]').focus(); return; }
    const id = 'custom-' + Date.now().toString(36);
    const submitBtn = document.getElementById('add-submit');
    submitBtn.disabled = true;
    const ok = await PanglotStore.addNode({
      parent_id: cat,
      node_id: id,
      node_name: title,
      prerequisites: prereq,
    });
    submitBtn.disabled = false;
    if (!ok) { alert('Ajout échoué'); return; }
    addForm.classList.remove('show');
    addForm.querySelector('[name=title]').value = '';
    addForm.querySelector('[name=native]').value = '';
    addForm.querySelector('[name=decks]').value = '';
    [...addForm.querySelectorAll('.prereq-check input')].forEach(x => x.checked = false);
    if (T.nodes.find(n => n.id === id)) {
      openPanel(id);
    } else {
      console.warn('[app] addNode: node', id, 'not found in refetched tree — backend may have assigned a different ID');
    }
  };

  // ===== menus =====
  function toggleMenu(menu, anchor) {
    const rect = anchor.getBoundingClientRect();
    menu.style.top = (rect.bottom + 6) + 'px';
    menu.style.left = 'auto';
    menu.style.right = (window.innerWidth - rect.right) + 'px';
    menu.classList.toggle('show');
  }
  document.addEventListener('click', (e) => {
    if (!e.target.closest('#lang-btn') && !e.target.closest('#lang-menu')) document.getElementById('lang-menu').classList.remove('show');
    if (!e.target.closest('#ui-lang-btn') && !e.target.closest('#ui-lang-menu')) document.getElementById('ui-lang-menu').classList.remove('show');
  });

  function buildLangMenu() {
    const m = document.getElementById('lang-menu');
    m.innerHTML = '';
    availableLangs.forEach(l => {
      const item = document.createElement('div');
      item.className = 'menu-item' + (T && l.iso === T.language.code ? ' on' : '');
      item.innerHTML = `<span class="flag">${getFlag(l.iso)}</span><span>${targetLangLabel(l.iso, l.autonym)}</span>`;
      item.onclick = async () => {
        await PanglotStore.loadLanguage(l.iso);
        m.classList.remove('show');
      };
      m.appendChild(item);
    });
  }
  function buildUiLangMenu() {
    const m = document.getElementById('ui-lang-menu');
    m.innerHTML = '';
    uiLangs.forEach(l => {
      const item = document.createElement('div');
      item.className = 'menu-item' + (l.code === currentUiLang ? ' on' : '');
      item.innerHTML = `<span style="font-family:var(--font-mono); font-size:10px; color:var(--ink-faded); width:22px;">${l.code.toUpperCase()}</span><span>${l.label}</span>`;
      item.onclick = async () => {
        await changeLocale(l.code);
        buildUiLangMenu(); buildLangMenu();
        if (T) populateAddSelects();
        m.classList.remove('show');
      };
      m.appendChild(item);
    });
  }
  document.getElementById('lang-btn').onclick = (e) => { e.stopPropagation(); buildLangMenu(); toggleMenu(document.getElementById('lang-menu'), e.currentTarget); };
  document.getElementById('ui-lang-btn').onclick = (e) => { e.stopPropagation(); buildUiLangMenu(); toggleMenu(document.getElementById('ui-lang-menu'), e.currentTarget); };

  // ===== theme =====
  function setTheme(mode, transitionPos) {
    const change = () => {
      document.documentElement.classList.toggle('dark', mode === 'dark');
      localStorage.setItem('panglot.theme', mode);
      const tw = document.querySelector('[data-tweak="theme"]');
      if (tw) tw.querySelectorAll('button').forEach(b => b.classList.toggle('on', b.dataset.v === mode));
    };

    if (transitionPos && document.startViewTransition) {
      const { x, y } = transitionPos;
      const endRadius = Math.hypot(Math.max(x, innerWidth - x), Math.max(y, innerHeight - y));
      const transition = document.startViewTransition(change);
      transition.ready.then(() => {
        document.documentElement.animate(
          {
            clipPath: [
              `circle(0px at ${x}px ${y}px)`,
              `circle(${endRadius}px at ${x}px ${y}px)`
            ]
          },
          {
            duration: 650,
            easing: 'ease-in-out',
            pseudoElement: '::view-transition-new(root)',
          }
        );
      });
    } else {
      change();
    }
  }

  document.getElementById('theme-btn').onclick = (e) => {
    const cur = document.documentElement.classList.contains('dark') ? 'dark' : 'light';
    setTheme(cur === 'dark' ? 'light' : 'dark', { x: e.clientX, y: e.clientY });
  };
  setTheme(localStorage.getItem('panglot.theme') || 'light');

  // ===== tweaks =====
  const DENSITY_VARS = {
    comfy: { '--mini-col-w': '248px', '--row-h': '132px', '--node-w': '228px' },
    tight: { '--mini-col-w': '210px', '--row-h': '112px', '--node-w': '196px' },
  };

  function applyTweak(key, val, transitionPos) {
    tweakState[key] = val;
    const container = document.querySelector(`[data-tweak="${key}"]`);
    if (container) container.querySelectorAll('button').forEach(b => b.classList.toggle('on', b.dataset.v === val));
    if (key === 'theme') setTheme(val, transitionPos);
    if (key === 'density') {
      const root = document.documentElement;
      const vars = DENSITY_VARS[val] || DENSITY_VARS.comfy;
      Object.entries(vars).forEach(([k, v]) => root.style.setProperty(k, v));
      readLayoutFromCss();
      if (T) {
        positions = computeLayout();
        renderLevels(); renderNodes(); renderEdges();
        fitView();
      }
    }
    if (key === 'zones') {
      document.documentElement.classList.toggle('zones-hidden', val === 'off');
    }
  }
  document.querySelectorAll('.tweak-options button').forEach(b => {
    b.onclick = (e) => {
      const key = b.closest('.tweak-options').dataset.tweak;
      applyTweak(key, b.dataset.v, { x: e.clientX, y: e.clientY });
      window.parent.postMessage({ type: '__edit_mode_set_keys', edits: { [key]: b.dataset.v } }, '*');
    };
  });
  window.addEventListener('message', (e) => {
    if (e.data?.type === '__activate_edit_mode') document.getElementById('tweaks').classList.add('show');
    else if (e.data?.type === '__deactivate_edit_mode') document.getElementById('tweaks').classList.remove('show');
  });
  window.parent.postMessage({ type: '__edit_mode_available' }, '*');

  // ===== store subscription =====
  let firstRender = true;
  PanglotStore.subscribe(tree => {
    T = tree;
    // Reset view state on tree reload
    viewMode = 'micro';
    activeCatFilter = null;
    macroLayer.style.display = 'none';
    nodesLayer.style.display = '';
    edgesLayer.style.display = '';
    levelsLayer.style.display = '';
    document.getElementById('view-breadcrumb').classList.add('hidden');
    document.getElementById('btn-add-node').style.display = '';
    document.getElementById('zoom-macro').classList.remove('on');
    positions = computeLayout();
    buildPrereqIndex();
    renderLevels(); renderNodes(); renderEdges();
    renderSidebar(); buildLangMenu();
    populateAddSelects();
    if (firstRender) {
      firstRender = false;
      requestAnimationFrame(() => { fitView(); focusFrontier(); });
    }
  });

  // ===== init =====
  async function startApp() {
    availableLangs = await PanglotAPI.fetchLanguages();
    const lang = new URLSearchParams(window.location.search).get('lang') || 'pol';
    await initI18n(currentUiLang);
    await changeLocale(currentUiLang);
    buildUiLangMenu();
    const ok = await PanglotStore.loadLanguage(lang);
    if (!ok) {
      document.body.innerHTML = '<div style="padding:40px;font-family:sans-serif">Failed to load tree. Is the server running?</div>';
    }
  }

  window._panglotPostAuthInit = startApp;

  (async () => {
    const authed = await PanglotAuth.init();
    if (!authed) return; // auth overlay is shown, waiting for login
    await startApp();
  })();
})();

