1	// Pluggable frontier algorithms. Change ACTIVE to switch strategy.
2	const PanglotFrontier = (() => {
3	  const level = n => n.palier + n.sub / 3;
4	
5	  const Algorithms = {
6	    simple_mean(nodes) {
7	      const ip = nodes.filter(n => n.status === 'in_progress');
8	      if (ip.length) return ip.reduce((s, n) => s + level(n), 0) / ip.length;
9	      const m = nodes.filter(n => n.status === 'mastered');
10	      if (m.length) return Math.max(...m.map(level)) + 0.5;
11	      return 0;
12	    },
13	
14	    weighted_mastery(nodes) {
15	      const ip = nodes.filter(n => n.status === 'in_progress' && (n.mastery || 0) > 0);
16	      if (ip.length) {
17	        const num = ip.reduce((s, n) => s + level(n) * n.mastery, 0);
18	        const den = ip.reduce((s, n) => s + n.mastery, 0);
19	        if (den > 0) return num / den;
20	      }
21	      const m = nodes.filter(n => n.status === 'mastered');
22	      if (m.length) return Math.max(...m.map(level)) + 0.5;
23	      return 0;
24	    },
25	
26	    median_filtered(nodes) {
27	      const m = nodes.filter(n => n.status === 'mastered');
28	      const ceiling = m.length ? Math.max(...m.map(level)) + 1 : Infinity;
29	      const ip = nodes
30	        .filter(n => n.status === 'in_progress' && (n.exercisesDone || 0) >= 3)
31	        .map(level)
32	        .sort((a, b) => a - b);
33	      if (ip.length) {
34	        const mid = Math.floor(ip.length / 2);
35	        const med = ip.length % 2 ? ip[mid] : (ip[mid - 1] + ip[mid]) / 2;
36	        return Math.min(med, ceiling);
37	      }
38	      if (m.length) return Math.max(...m.map(level)) + 0.5;
39	      return 0;
40	    },
41	  };
42	
43	  const ACTIVE = 'median_filtered';
44	
45	  function compute(nodes) { return Algorithms[ACTIVE](nodes); }
46	
