// Central state store. Pub/sub. All tree mutations funnel through here.
const PanglotStore = (() => {
  let _tree = null;
  const _subs = [];
  let _inflight = Promise.resolve();

  function getState() { return _tree; }

  function subscribe(cb) {
    _subs.push(cb);
    return () => { const i = _subs.indexOf(cb); if (i >= 0) _subs.splice(i, 1); };
  }

  function _notify() { _subs.forEach(cb => { try { cb(_tree); } catch (e) { console.error('[store] subscriber threw', e); } }); }

  function setTree(tree) { _tree = tree; _notify(); }

  async function loadLanguage(langCode) {
    const tree = await PanglotAPI.fetchTree(langCode);
    if (tree) { setTree(tree); return true; }
    return false;
  }

  function _refetch() {
    if (!_tree) return Promise.resolve();
    return (_inflight = _inflight
      .then(() => PanglotAPI.fetchTree(_tree.language.code).then(t => { if (t) setTree(t); }))
      .catch(err => console.error('[store] refetch failed', err))
    );
  }

  async function addNode(req) {
    if (!_tree) return false;
    const ok = await PanglotAPI.addNode({ ...req, language: _tree.language.code });
    if (ok) await _refetch();
    return ok;
  }

  async function hideNode(node_id) {
    if (!_tree) return false;
    const ok = await PanglotAPI.hideNode({ language: _tree.language.code, node_id });
    if (ok) await _refetch();
    return ok;
  }

  async function editNode(req) {
    if (!_tree) return false;
    const ok = await PanglotAPI.editNode({ language: _tree.language.code, ...req });
    if (ok) await _refetch();
    return ok;
  }

  async function deleteCustomization(node_id) {
    if (!_tree) return false;
    const ok = await PanglotAPI.deleteCustomization(_tree.language.code, node_id);
    if (ok) await _refetch();
    return ok;
  }

  return { getState, subscribe, loadLanguage, addNode, hideNode, editNode, deleteCustomization };
})();

