const PanglotAuth = (() => {
  let _supabase = null;

  function showOverlay() {
    const el = document.getElementById('auth-overlay');
    if (el) el.classList.remove('hidden');
  }
  function hideOverlay() {
    const el = document.getElementById('auth-overlay');
    if (el) el.classList.add('hidden');
  }
  function setError(msg) {
    const el = document.getElementById('auth-error');
    if (el) el.textContent = msg || '';
  }
  // TODO vérifier
  async function init() {
    let config;
    try {
      const res = await fetch('/api/auth/config');
      if (!res.ok) return true; // solo mode on server error
      config = await res.json();
    } catch (e) {
      return true; // solo mode if unreachable
    }

    if (!config.enabled) return true; // solo mode

    try {
      _supabase = window.supabase.createClient(config.supabase_url, config.supabase_anon_key);
    } catch (e) {
      console.warn('[PanglotAuth] Supabase init failed, falling back to solo mode', e);
      return true;
    }

    const { data: { session } } = await _supabase.auth.getSession();
    if (!session) {
      showOverlay();
      return false;
    }

    PanglotAPI.setToken(session.access_token);
    try {
      await fetch('/api/auth/login', {
        method: 'POST',
        headers: { 'Authorization': 'Bearer ' + session.access_token },
      });
    } catch (e) { /* non-fatal */ }

    return true;
  }

  async function login() {
    const email = document.getElementById('auth-email')?.value?.trim();
    const password = document.getElementById('auth-password')?.value;
    if (!email || !password) { setError('Email and password required'); return; }
    if (!_supabase) { setError('Auth not initialized'); return; }

    setError('');
    const { data, error } = await _supabase.auth.signInWithPassword({ email, password });
    if (error) { setError(error.message); return; }

    PanglotAPI.setToken(data.session.access_token);
    try {
      await fetch('/api/auth/login', {
        method: 'POST',
        headers: { 'Authorization': 'Bearer ' + data.session.access_token },
      });
    } catch (e) { /* non-fatal */ }

    hideOverlay();
    // Re-init the app after successful login
    if (typeof window._panglotPostAuthInit === 'function') window._panglotPostAuthInit();
  }

  async function logout() {
    if (_supabase) await _supabase.auth.signOut();
    PanglotAPI.setToken(null);
    showOverlay();
  }

  return { init, login, logout };
})();

