const level = n => n.palier + n.sub / 3;

const Algorithms = {
  simple_mean(nodes) {
    const ip = nodes.filter(n => n.status === 'in_progress');
    if (ip.length) return ip.reduce((s, n) => s + level(n), 0) / ip.length;
    const m = nodes.filter(n => n.status === 'mastered');
    if (m.length) return Math.max(...m.map(level)) + 0.5;
    return 0;
  },

  weighted_mastery(nodes) {
    const ip = nodes.filter(n => n.status === 'in_progress' && (n.mastery || 0) > 0);
    if (ip.length) {
      const num = ip.reduce((s, n) => s + level(n) * n.mastery, 0);
      const den = ip.reduce((s, n) => s + n.mastery, 0);
      if (den > 0) return num / den;
    }
    const m = nodes.filter(n => n.status === 'mastered');
    if (m.length) return Math.max(...m.map(level)) + 0.5;
    return 0;
  },

  median_filtered(nodes) {
    const m = nodes.filter(n => n.status === 'mastered');
    const ceiling = m.length ? Math.max(...m.map(level)) + 1 : Infinity;
    const ip = nodes
      .filter(n => n.status === 'in_progress' && (n.exercisesDone || 0) >= 3)
      .map(level)
      .sort((a, b) => a - b);
    if (ip.length) {
      const mid = Math.floor(ip.length / 2);
      const med = ip.length % 2 ? ip[mid] : (ip[mid - 1] + ip[mid]) / 2;
      return Math.min(med, ceiling);
    }
    if (m.length) return Math.max(...m.map(level)) + 0.5;
    return 0;
  },
};

const ACTIVE = 'median_filtered';

export function compute(nodes) { return Algorithms[ACTIVE](nodes); }
export { Algorithms, level, ACTIVE };

