import { compute as computeFrontier } from './frontier.js';

const BASE = '';
let _token = null;
let _cachedLangs = null;

function headers() {
  const h = { 'Content-Type': 'application/json' };
  if (_token) h['Authorization'] = 'Bearer ' + _token;
  return h;
}

export function setToken(t) { _token = t; }

// ── Layout computation ────────────────────────────────────────────

function buildCategories(rootChildren) {
  const hues = [28, 255, 155, 345, 75, 200, 310, 90];
  return rootChildren.map((cat, i) => ({
    id: cat.id,
    name: cat.name,
    hue: hues[i % hues.length],
    concept_key: cat.concept_key || null,
  }));
}

function buildCategoryMap(rootChildren) {
  const map = {};
  function assign(node, catId) {
    map[node.id] = catId;
    (node.children || []).forEach(c => assign(c, catId));
  }
  rootChildren.forEach(cat => assign(cat, cat.id));
  return map;
}

function flattenTree(root) {
  const nodes = [];
  function walk(node) {
    if (node.id !== root.id) nodes.push(node);
    (node.children || []).forEach(walk);
  }
  walk(root);
  return nodes;
}

function buildLayoutMap(flatNodes) {
  const uniqueTiers = [...new Set(flatNodes.map(n => n.tier))].sort((a, b) => a - b);
  const n = uniqueTiers.length || 1;

  function tierToPalier(tier) {
    const rank = uniqueTiers.indexOf(tier);
    return Math.min(Math.floor(rank * 5 / n), 4);
  }

  const palierTiers = [[], [], [], [], []];
  uniqueTiers.forEach(tier => palierTiers[tierToPalier(tier)].push(tier));

  const layoutMap = {};
  flatNodes.forEach(node => {
    const palier = tierToPalier(node.tier);
    const sub = palierTiers[palier].indexOf(node.tier) % 3;
    layoutMap[node.id] = { palier, sub };
  });
  return layoutMap;
}

// ── fetchTree ─────────────────────────────────────────────────────

export async function fetchTree(lang) {
  let root;
  try {
    const res = await fetch(`${BASE}/api/tree?lang=${lang}`, { headers: headers() });
    if (!res.ok) return null;
    root = await res.json();
  } catch (e) {
    console.warn('[PanglotAPI] GET /api/tree failed', e);
    return null;
  }

  const categories = buildCategories(root.children || []);
  const categoryMap = buildCategoryMap(root.children || []);
  const flatNodes = flattenTree(root);
  const layoutMap = buildLayoutMap(flatNodes);

  const nodes = flatNodes.map(n => ({
    id: n.id,
    name: n.name,
    desc: n.desc || null,
    native: '',
    category: categoryMap[n.id] || null,
    palier: layoutMap[n.id]?.palier ?? 0,
    sub: layoutMap[n.id]?.sub ?? 0,
    tier: n.tier,
    prereq: n.prerequisites || [],
    is_generatable: n.is_generatable,
    mastery: n.mastery ?? 0,
    status: n.status ?? 'fresh',
    exercisesDone: n.exercises_done ?? 0,
    lastPracticed: null,
    decks: [],
  }));

  const paliers = [
    { label: { fr: 'Niveau 1', en: 'Level 1', de: 'Stufe 1' } },
    { label: { fr: 'Niveau 2', en: 'Level 2', de: 'Stufe 2' } },
    { label: { fr: 'Niveau 3', en: 'Level 3', de: 'Stufe 3' } },
    { label: { fr: 'Niveau 4', en: 'Level 4', de: 'Stufe 4' } },
    { label: { fr: 'Niveau 5', en: 'Level 5', de: 'Stufe 5' } },
  ];

  const userFrontier = computeFrontier(nodes);

  return {
    language: { code: lang, native: root.name },
    nodes,
    categories,
    paliers,
    userFrontier,
    nodeLevel: n => n.palier + n.sub / 3,
  };
}

// ── generateForNode ───────────────────────────────────────────────

export async function generateForNode(nodeId, lang) {
  const res = await fetch(`${BASE}/api/generate`, {
    method: 'POST',
    headers: headers(),
    body: JSON.stringify({
      node_id: nodeId,
      language: lang,
      user_profile: {
        ui_language: 'English',
        linguistic_background: [],
        srs_algorithm: 'sm2',
        learn_ahead_minutes: 20,
      },
    }),
  });
  return res.json();
}

// ── customization mutations ──────────────────────────────────────

async function _postJson(path, body) {
  try {
    const res = await fetch(`${BASE}${path}`, {
      method: 'POST',
      headers: headers(),
      body: JSON.stringify(body),
    });
    if (!res.ok) return false;
    const data = await res.json();
    return !!data.success;
  } catch (e) {
    console.warn(`[PanglotAPI] POST ${path} failed`, e);
    return false;
  }
}

export async function addNode(req) { return _postJson('/api/add-node', req); }
export async function hideNode(req) { return _postJson('/api/hide-node', req); }
export async function editNode(req) { return _postJson('/api/edit-node', req); }

export async function deleteCustomization(lang, nodeId) {
  try {
    const res = await fetch(`${BASE}/api/tree-customization?lang=${encodeURIComponent(lang)}&node_id=${encodeURIComponent(nodeId)}`, {
      method: 'DELETE',
      headers: headers(),
    });
    if (!res.ok) return false;
    const data = await res.json();
    return !!data.success;
  } catch (e) {
    console.warn('[PanglotAPI] DELETE /api/tree-customization failed', e);
    return false;
  }
}

export async function fetchLanguages() {
  if (_cachedLangs) return _cachedLangs;
  try {
    const res = await fetch(`${BASE}/api/languages`);
    if (!res.ok) return [];
    _cachedLangs = await res.json();
    return _cachedLangs;
  } catch (e) {
    console.warn('[PanglotAPI] GET /api/languages failed', e);
    return [];
  }
}

