  const tree = await API.fetchTree(langCode);
  if (tree) { setTree(tree); return true; }
  return false;
}

function _refetch() {
  if (!_tree) return Promise.resolve();
  return (_inflight = _inflight
    .then(() => API.fetchTree(_tree.language.code).then(t => { if (t) setTree(t); }))
    .catch(err => console.error('[store] refetch failed', err))
  );
}

export async function addNode(req) {
  if (!_tree) return false;
  const ok = await API.addNode({ ...req, language: _tree.language.code });
  if (ok) await _refetch();
  return ok;
}

export async function hideNode(node_id) {
  if (!_tree) return false;
  const ok = await API.hideNode({ language: _tree.language.code, node_id });
  if (ok) await _refetch();
  return ok;
}

export async function editNode(req) {
  if (!_tree) return false;
  const ok = await API.editNode({ language: _tree.language.code, ...req });
  if (ok) await _refetch();
  return ok;
}

export async function deleteCustomization(node_id) {
  if (!_tree) return false;
  const ok = await API.deleteCustomization(_tree.language.code, node_id);
  if (ok) await _refetch();
  return ok;
}

