import { createClient } from '@supabase/supabase-js';
import { setToken } from './api.js';

let _supabase = null;
let _postLoginCallback = null;

export function setPostLoginCallback(fn) { _postLoginCallback = fn; }

function showOverlay() { document.getElementById('auth-overlay')?.classList.remove('hidden'); }
function hideOverlay() { document.getElementById('auth-overlay')?.classList.add('hidden'); }
function setError(msg) { const el = document.getElementById('auth-error'); if (el) el.textContent = msg || ''; }

export async function init() {
  let config;
  try {
    const res = await fetch('/api/auth/config');
    if (!res.ok) return true;
    config = await res.json();
  } catch {
    return true;
  }

  if (!config.enabled) return true;

  try {
    _supabase = createClient(config.supabase_url, config.supabase_anon_key);
  } catch (e) {
    console.warn('[PanglotAuth] Supabase init failed, falling back to solo mode', e);
    return true;
  }

  const { data: { session } } = await _supabase.auth.getSession();
  if (!session) {
    showOverlay();
    return false;
  }

  setToken(session.access_token);
  try {
    await fetch('/api/auth/login', {
      method: 'POST',
      headers: { 'Authorization': 'Bearer ' + session.access_token },
    });
  } catch { /* non-fatal */ }

  return true;
}

export async function login() {
  const email = document.getElementById('auth-email')?.value?.trim();
  const password = document.getElementById('auth-password')?.value;
  if (!email || !password) { setError('Email and password required'); return; }
  if (!_supabase) { setError('Auth not initialized'); return; }

  setError('');
  const { data, error } = await _supabase.auth.signInWithPassword({ email, password });
  if (error) { setError(error.message); return; }

  setToken(data.session.access_token);
  try {
    await fetch('/api/auth/login', {
      method: 'POST',
      headers: { 'Authorization': 'Bearer ' + data.session.access_token },
    });
  } catch { /* non-fatal */ }

  hideOverlay();
  if (_postLoginCallback) _postLoginCallback();
}

export async function logout() {
  if (_supabase) await _supabase.auth.signOut();
  setToken(null);
  showOverlay();
}

