import { state } from './state.js';

export const LAYOUT = { miniColW: 0, rowH: 0, padLeft: 0, padTop: 0, nodeW: 0 };
export const SUBS_PER_PALIER = 3;

export function readLayoutFromCss() {
  const cs = getComputedStyle(document.documentElement);
  const read = k => parseFloat(cs.getPropertyValue(k));
  LAYOUT.miniColW = read('--mini-col-w');
  LAYOUT.rowH = read('--row-h');
  LAYOUT.nodeW = read('--node-w');
  LAYOUT.padLeft = read('--pad-left');
  LAYOUT.padTop = read('--pad-top');
}

export function palierX(palier) { return LAYOUT.padLeft + palier * SUBS_PER_PALIER * LAYOUT.miniColW; }
export function nodeX(n) { return palierX(n.palier) + n.sub * LAYOUT.miniColW; }

export function computeLayout() {
  const T = state.tree;
  const groups = {};
  T.nodes.forEach(n => {
    const key = `${n.palier}_${n.sub}`;
    (groups[key] = groups[key] || []).push(n);
  });
  const catOrder = Object.fromEntries(T.categories.map((c, i) => [c.id, i]));
  const positions = {};
  Object.values(groups).forEach(list => {
    list.sort((a, b) => (catOrder[a.category] ?? 999) - (catOrder[b.category] ?? 999));
    list.forEach((n, idx) => {
      positions[n.id] = {
        x: nodeX(n),
        y: LAYOUT.padTop + idx * LAYOUT.rowH,
      };
    });
  });
  return positions;
}

export function buildPrereqIndex() {
  const index = {};
  state.tree.nodes.forEach(n => {
    (n.prereq || []).forEach(pid => {
      (index[pid] = index[pid] || new Set()).add(n.id);
    });
  });
  state.prereqIndex = index;
}

export function fitZone(n) {
  const T = state.tree;
  const lvl = T.nodeLevel(n);
  const d = lvl - T.userFrontier;
  if (n.status === 'mastered') return 'review';
  if (d < -0.3) return 'review';
  if (d <= 0.6) return 'in_zone';
  if (d <= 1.5) return 'ahead';
  return 'beyond';
}

