import { state } from './state.js';
import { uiLangs, getFlag, targetLangLabel, changeLocale } from './i18n.js';
import * as Store from './store.js';

function toggleMenu(menu, anchor) {
  const rect = anchor.getBoundingClientRect();
  menu.style.top = (rect.bottom + 6) + 'px';
  menu.style.left = 'auto';
  menu.style.right = (window.innerWidth - rect.right) + 'px';
  menu.classList.toggle('show');
}

export function buildLangMenu() {
  const m = document.getElementById('lang-menu');
  m.innerHTML = '';
  state.availableLangs.forEach(l => {
    const item = document.createElement('div');
    item.className = 'menu-item' + (state.tree && l.iso === state.tree.language.code ? ' on' : '');
    item.innerHTML = `<span class="flag">${getFlag(l.iso)}</span><span>${targetLangLabel(l.iso, l.autonym)}</span>`;
    item.onclick = async () => {
      await Store.loadLanguage(l.iso);
      m.classList.remove('show');
    };
    m.appendChild(item);
  });
}

export function buildUiLangMenu() {
  const m = document.getElementById('ui-lang-menu');
  m.innerHTML = '';
  uiLangs.forEach(l => {
    const item = document.createElement('div');
    item.className = 'menu-item' + (l.code === state.currentUiLang ? ' on' : '');
    item.innerHTML = `<span style="font-family:var(--font-mono); font-size:10px; color:var(--ink-faded); width:22px;">${l.code.toUpperCase()}</span><span>${l.label}</span>`;
    item.onclick = async () => {
      await changeLocale(l.code);
      buildUiLangMenu();
      buildLangMenu();
      m.classList.remove('show');
    };
    m.appendChild(item);
  });
}

export function initMenuControls() {
  document.getElementById('lang-btn').onclick = (e) => {
    e.stopPropagation();
    buildLangMenu();
    toggleMenu(document.getElementById('lang-menu'), e.currentTarget);
  };
  document.getElementById('ui-lang-btn').onclick = (e) => {
    e.stopPropagation();
    buildUiLangMenu();
    toggleMenu(document.getElementById('ui-lang-menu'), e.currentTarget);
  };
  document.addEventListener('click', (e) => {
    if (!e.target.closest('#lang-btn') && !e.target.closest('#lang-menu')) {
      document.getElementById('lang-menu').classList.remove('show');
    }
    if (!e.target.closest('#ui-lang-btn') && !e.target.closest('#ui-lang-menu')) {
      document.getElementById('ui-lang-menu').classList.remove('show');
    }
  });
}

